def clean_metadata(raw_data):
    cleaned = []
    for record in raw_data:
        item = {
            "id": int(record.get("id", 0)),
            "name": record.get("name") or record.get("prod_name") or record.get("product"),
            "price": float(record.get("price_usd", 0)) if "price_usd" in record else (float(record.get("price", 0)) if record.get("price") is not None else 0.0),
            "active": ("ACTIVE" in record.get("status", "")) or (record.get("status") == "ACTIVE") or (record.get("active") == True)
        }
        cleaned.append(item)
    return cleaned
